}

.goal-dialog-overlay.hidden {
    display: none;
}

.goal-dialog {
    padding: 20px;
    background: #141414;
    border-radius: 24px;
    max-width: 500px;
    border: 3px solid black;
    width: 85%;
    max-height: 85vh;
    box-shadow: 0 24px 48px rgba(0, 0, 0, 0.4);
    animation: slideIn 0.3s ease-out;
    display: flex;
    flex-direction: column;
    font-family: "Nunito", sans-serif;
    color: white;
}

.goal-dialog-header {
    background-size: cover;
    background-position: center;
    background-repeat: no-repeat;
    color: white;
    border-radius: 24px 24px 0 0;
    text-align: center;
    position: relative;
}

.goal-dialog-header h2 {
    font-size: 2.5rem;
    font-weight: 900;
}

.goal-dialog-header h3 {
    font-weight: normal;
    opacity: 0.8;
    margin-top: 6px;
}

.goal-dialog-goals {
    display: flex;
    gap: 12px;
    justify-content: center;
    flex-wrap: wrap;
}

@keyframes bounceIn {
    0% {
        opacity: 0;
        transform: scale(0.3);
    }
    50% {
        opacity: 1;
        transform: scale(1.05);
    }
    70% {
        transform: scale(0.9);
    }
    100% {
        transform: scale(1);
    }
}

.goal-dialog-goals .goal-card {
    animation: bounceIn 0.5s ease-out;
    scale: 1.2;
}

div#featureUnlockDialog {
    background: url(assets/confetti.png), rgba(0, 0, 0, 0.85);
    background-size: contain;
    background-repeat: no-repeat;

    .goal-dialog-content {
        background: url("assets/rays.png");
        background-position: center center;
        background-size: contain;
        background-repeat: no-repeat;
        padding: 36px 0px 10px;
    }
}

.goal-dialog-content {
    padding: 20px 0px;
    margin-bottom: 12px;
    overflow: hidden;
    color: #333;
    flex: 1;
    display: flex;
    justify-content: center;
}

.goal-dialog-content p {
    margin: 0 0 15px 0;
    line-height: 1.6;
}

.goal-dialog-content p:last-child {
    margin-bottom: 0;
}

.goal-dialog-content strong {
    color: #667eea;
    font-weight: 600;
}

.goal-dialog-content ul {
    margin: 15px 0;
    padding-left: 25px;
}

.goal-dialog-content li {
    margin: 8px 0;
    line-height: 1.5;
}

.goal-dialog-content em {
    display: block;
    margin-top: 15px;
    padding: 12px;
    background: #f0f4ff;
    border-left: 4px solid #667eea;
    border-radius: 8px;
    font-style: normal;
    color: #555;
}

.goal-dialog-footer {
    border-radius: 0 0 24px 24px;
    display: flex;
    justify-content: center;
}

.goal-dialog-button {
    background: #aee96b;
    box-shadow: 0 -4px 0 0 rgba(0, 0, 0, 0.25) inset;
    color: black;
    border: none;
    padding: 12px 32px;
    border-radius: 10px;
    font-size: clamp(26px, 8vw, 40px);
    font-weight: 900;
    cursor: pointer;
    transition: all 0.2s;
    font-family: "Nunito", sans-serif;
    width: 100%;
}

.goal-dialog-button:active {
    transform: translateY(0);
}

.give-up-confirm-btn {
    background: #450a0a !important;
    color: #fff !important;
}

.give-up-losses {
    width: 100%;
    display: flex;
    flex-direction: column;
}

.loss-item {
    display: grid;
    grid-template-columns: clamp(32px, 8vw, 40px) 1fr;
    align-items: center;
    gap: 12px;
    color: rgba(255, 255, 255, 0.9);
    font-family: "Nunito", sans-serif;
    font-size: clamp(16px, 4vw, 20px);
    font-weight: 700;

